css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f0fdfa; color: #134e4a; }
header { background: white; border-bottom: 1px solid #ccfbf1; position: sticky; top: 0; z-index: 100; }
nav { display: flex; align-items: center; justify-content: space-between; max-width: 1100px; margin: 0 auto; padding: 0 28px; height: 64px; }
.logo { font-size: 20px; font-weight: 800; color: #0d9488; }
.links { display: flex; gap: 24px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; font-size: 14px; } .links a:hover { color: #0d9488; }
.follow-btn { padding: 8px 18px; border-radius: 20px; border: none; background: #0d9488; color: white; font-weight: 700; cursor: pointer; font-size: 13px; }
.hero-post { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: center; max-width: 1100px; margin: 0 auto; padding: 56px 28px; border-bottom: 1px solid #ccfbf1; }
.hp-tags { display: flex; gap: 8px; margin-bottom: 16px; }
.tag { padding: 4px 12px; border-radius: 20px; background: #ccfbf1; color: #0d9488; font-size: 12px; font-weight: 700; }
h1 { font-size: 36px; font-weight: 800; line-height: 1.2; margin-bottom: 14px; }
.hp-content p { color: #6b7280; font-size: 16px; line-height: 1.75; margin-bottom: 20px; }
.hp-meta { display: flex; justify-content: space-between; align-items: center; }
.author { display: flex; gap: 10px; align-items: center; }
.av { width: 36px; height: 36px; border-radius: 50%; background: linear-gradient(135deg, #0d9488, #0891b2); display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 800; color: white; }
.author strong { display: block; font-size: 14px; } .author small { color: #9ca3af; font-size: 12px; }
.meta-stats { display: flex; gap: 12px; font-size: 14px; color: #9ca3af; }
.map-preview { height: 280px; background: linear-gradient(135deg, #0e7490, #0d9488, #0891b2); border-radius: 20px; display: flex; align-items: center; justify-content: center; font-size: 80px; position: relative; overflow: hidden; }
.map-pin { position: absolute; background: white; color: #0d9488; padding: 4px 10px; border-radius: 20px; font-size: 12px; font-weight: 700; box-shadow: 0 2px 8px rgba(0,0,0,0.2); }
.destinations { padding: 56px 28px; max-width: 1100px; margin: 0 auto; border-bottom: 1px solid #ccfbf1; }
.destinations h2 { font-size: 28px; font-weight: 800; margin-bottom: 24px; }
.dest-grid { display: grid; grid-template-columns: repeat(6, 1fr); gap: 14px; }
.dest-card { background: white; border-radius: 16px; overflow: hidden; cursor: pointer; transition: all 0.2s; border: 1px solid #e2e8f0; } .dest-card:hover { transform: translateY(-3px); box-shadow: 0 8px 20px rgba(13,148,136,0.12); }
.dc-img { height: 80px; background: linear-gradient(135deg, #ccfbf1, #a7f3d0); display: flex; align-items: center; justify-content: center; font-size: 36px; }
.dc-info { padding: 10px; } .dc-info strong { display: block; font-size: 13px; font-weight: 700; } .dc-info span { color: #9ca3af; font-size: 11px; display: block; margin-bottom: 6px; }
.dc-tag { display: inline-block; padding: 2px 8px; border-radius: 6px; background: #ccfbf1; color: #0d9488; font-size: 10px; font-weight: 700; }
.recent-posts { padding: 56px 28px 72px; max-width: 1100px; margin: 0 auto; }
.recent-posts h2 { font-size: 28px; font-weight: 800; margin-bottom: 24px; }
.posts-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
.post-card { background: white; border-radius: 16px; overflow: hidden; border: 1px solid #e2e8f0; cursor: pointer; transition: all 0.2s; } .post-card:hover { transform: translateY(-3px); box-shadow: 0 8px 20px rgba(0,0,0,0.08); }
.pc-img { height: 160px; display: flex; align-items: center; justify-content: center; font-size: 60px; }
.pc-info { padding: 16px; }
.pc-tags { display: flex; gap: 6px; margin-bottom: 10px; }
.pc-info h3 { font-size: 16px; font-weight: 700; margin-bottom: 6px; line-height: 1.35; } .pc-info p { color: #9ca3af; font-size: 13px; margin-bottom: 12px; }
.pc-meta { display: flex; gap: 12px; font-size: 12px; color: #9ca3af; }
